head.script:
// ASIS : 조회하지 않고 엑셀업로드하면 데이터셋에 bookingNo, blNo 컬럼이 없어서 데이터 SET 안됨
scwin.strPreDate = $c.date.addMonth($c.date.getServerDateTime("yyyyMMdd"), -1); // 1달전
scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");// 현재일자
scwin.olddata = "";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    ds_cond.set("arrvlportDtm", scwin.strPreDate);
    ds_cond.set("arrvlportDtmTo", scwin.strCurDate);

    // 공통코드 콤보박스 SET
    const codeOptions = [
        { grpCd: "OP524", compID: "gr_out:term" },      //그리드 : TERM
        { grpCd: "SD133", compID: "gr_out:offRtrn" }    //그리드 : OFF반납
    ];
    $c.data.setCommonCode(codeOptions);

    // 입력 그리드 maxlength 설정
    scwin.f_SetGridColumnMaxLength(gr_out);

    //테스트 데이터
    // ds_cond.set("arrvlportDtm", "20260101");
    // ds_cond.set("arrvlportDtmTo", "20260215");
    // ds_cond.set("lobranCd", "6P90");
};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    $p.setTimeout(function () {
        console.log("onUdcCompleted");
        ed_arrvlportDtm.focus();
    }, { "delay": 50 });
};

//-------------------------------------------------------------------------
// 입력 그리드 maxlength 설정
//-------------------------------------------------------------------------
scwin.f_SetGridColumnMaxLength = function (gridViewObj) {
    for (let i = 0; i < gridViewObj.getTotalCol(); i++) {
        let colNm = gridViewObj.getColumnID(i);
        let dataObj = $c.gus.object(gridViewObj.getDataList());
        let colInfo = dataObj.getColumnInfo(colNm);

        if (typeof colInfo != "undefined") {
            gridViewObj.setMaxLength(i, colInfo.length);
        }
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    let ret = await $c.gus.cfValidate([ed_arrvlportDtm, ed_arrvlportDtmTo])
    if (!ret) {
        return;
    }

    if (ed_wrkPlCd.getValue() == "" && ed_lineCd.getValue() == "" && ed_cntrNo.getValue() == "") {
        $c.win.alert("작업장, 라인, 컨테이너번호 중 1개는 입력해야 조회할 수 있습니다. 입항일자로만 조회할 경우 1달 기준 3만건이 넘어서 조회되지 않습니다.");
        return false;
    }

    if (!$c.gus.cfIsAfterDate(ed_arrvlportDtm.getValue(), ed_arrvlportDtmTo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_arrvlportDtm.focus();
        return false;
    }

    ds_out.setJSON([]);
    $c.sbm.execute(sbm_retrieve); //tr_retrieve.Post();
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if (ds_out.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_049, ["변경사항"]);
        return;
    }

    let validArry = [
        { id: "cntrNo", name: "컨테이너번호", mandatory: true, key: true }
    ];
    let gridName = "컨테이너 제어내역";

    if (!await $c.gus.cfValidateGrid(gr_out, null, null, validArry, gridName)) {
        return false;
    }

    //if (covGridValidExp([gr_out])) return;
    ret = await $c.win.confirm(MSG_CM_CRM_001);

    if (ret) {
        $c.sbm.execute(sbm_save);    //tr_save.Post();
    }
};

//-------------------------------------------------------------------------
// 조회조건 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search, null);
};

//-------------------------------------------------------------------------
// 행추가
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
    $c.data.insertRow("gr_out");
    tbx_totalRows.setValue(ds_out.getRowCount());
};

//-------------------------------------------------------------------------
// 행취소
//-------------------------------------------------------------------------
scwin.f_CanRow = function () {
    $c.data.undoRow(ds_out, false);
    tbx_totalRows.setValue(ds_out.getRowCount());
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;
    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);
    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);
    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        // 작업장
        case 1:
            udc_wkrPl.setSelectId("retrieveWrkPlInfo"); // XML상의 SELECT ID
            udc_wkrPl.cfCommonPopUp(scwin.udc_wkrPl_callBackFunc    // 팝업 콜백
                , pCode                           // 화면에서의 ??? Code Element의 Value
                , pName                           // 화면에서의 ??? Name Element의 Value
                , pClose                          // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                            // Title순서
                , null                            // 보여주는 각 컬럼들의 폭
                , null                            // 컬럼중에서 숨기는 컬럼 지정
                , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                , null                            // 윈도우 위치 Y좌표
                , null                            // 윈도우 위치 X좌표
                , null                            // 중복체크여부	("F")
                , pAllSearch                      // 전체검색허용여부	("F")
                , "작업장조회,작업장코드,작업장명"    // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
            );
            break;

        // 라인
        case 2:
            udc_line.setSelectId("retrieveLineInfo");   // XML상의 SELECT ID
            udc_line.cfCommonPopUp(scwin.udc_line_callBackFunc	// 팝업 콜백
                , pCode					    // 화면에서의 ??? Code Element의 Value
                , pName					    // 화면에서의 ??? Name Element의 Value
                , pClose					    // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                , null					        // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					        // Title순서
                , null					        // 보여주는 각 컬럼들의 폭
                , null					        // 컬럼중에서 숨기는 컬럼 지정
                , null					        // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null					        // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null					        // POP-UP뛰을때 윈도우의 사용자 정의 높이
                , null					        // 윈도우 위치 Y좌표
                , null					        // 윈도우 위치 X좌표
                , null					        // 중복체크여부	("F")
                , pAllSearch				    // 전체검색허용여부	("F")
                , "라인조회,라인코드,라인명"	// POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
            );
            break;
        // 현위치
        case 3:
            udc_comCode1.setSelectId("retrieveWrkPlInfo"); // XML상의 SELECT ID
            await udc_comCode1.cfCommonPopUpAsync(scwin.udc_gr_uploadComCode_callBackFunc	// 콜백 함수
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서
                , null					// 보여주는 각 컬럼들의 폭
                , null					// 컬럼중에서 숨기는	컬럼 지정
                , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 ㅇ도우의	사용자 정의	높이
                , null					// 윈도우 위치 Y좌표
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch				// 전체검색허용여부	("F")
                , "현위치조회,현위치코드,현위치명"	// POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
            );

            break;
    }
};

//-------------------------------------------------------------------------
// 작업장코드 UDC START
//-------------------------------------------------------------------------
scwin.udc_wkrPl_onclickEvent = async function (e) {
    scwin.f_openCommonPopUp(1, ed_wrkPlCd.getValue(), ed_wrkPlNm.getValue(), 'F', 'F');
};

scwin.udc_wkrPl_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_wrkPlCd, ed_wrkPlNm, 1);
};

scwin.udc_wkrPl_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_wrkPlNm, ed_wrkPlCd, 1, false);
};

scwin.udc_wkrPl_callBackFunc = function (ret) {
    $c.gus.cfSetReturnValue(ret, ed_wrkPlCd, ed_wrkPlNm);
};
//-------------------------------------------------------------------------
// 작업장코드 UDC END
//-------------------------------------------------------------------------

//-------------------------------------------------------------------------
// LINE코드 UDC START
//-------------------------------------------------------------------------
scwin.udc_line_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_lineCd.getValue(), ed_lineNm.getValue(), 'F', 'F');
};

scwin.udc_line_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_lineCd, ed_lineNm, 2);
};

scwin.udc_line_onviewchangeNameEvent = function (info) {
    f_chkOpenCommonPopUp(ed_lineNm, ed_lineCd, 2, false);
};

scwin.udc_line_callBackFunc = function (ret) {
    $c.gus.cfSetReturnValue(ret, ed_lineCd, ed_lineNm);
};
//-------------------------------------------------------------------------
// LINE코드 UDC END
//-------------------------------------------------------------------------


//-------------------------------------------------------------------------
// 엑셀 업로드
//-------------------------------------------------------------------------
scwin.f_upload = async function () {
    ds_out.setJSON([]);
    ds_excel.setJSON([]);

    let options = {
        "fileName": "gridDataUpload.xlsx",
        "status": "C",
        "headerExist": 1,
        "useMaxByteLength": ",",
        "type": "1",
        "startRowIndex": 0,
        "footerExist": "0"
    };

    await $c.data.uploadGridViewExcel(gr_excel, options);
};

//-------------------------------------------------------------------------
// 엑셀 업로드 후 데이터 검사
//-------------------------------------------------------------------------
scwin.gr_excel_onfilereadend = async function (value) {
    if (ds_excel.getRowCount() === 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return;
    }

    if (ds_excel.getTotalCol() !== 6) {
        $c.gus.cfAlertMsg("적재된 파일 자료가 UPLOAD형식에 일치하지 않습니다.");
        ds_excel.setJSON([]);
        return;
    }

    for (var i = 0; i < ds_excel.getRowCount(); i++) {
        await scwin.f_AddRowUploaded(i);
    }

    tbx_totalRows.setValue(ds_out.getRowCount())
};

//-------------------------------------------------------------------------
// 업로드된 데이터 추가 함수
//-------------------------------------------------------------------------
scwin.f_AddRowUploaded = async function (i) {
    let newRow = ds_out.insertRow();
    ds_out.setRowPosition(newRow);

    await scwin.f_retrieveCntrBasisInfo(ds_excel.getCellData(i, 0).trim());

    if ($c.gus.cfIsNull(ds_excel.getCellData(i, 1).trim()) &&
        $c.gus.cfIsNull(ds_excel.getCellData(i, 2).trim()) &&
        $c.gus.cfIsNull(ds_excel.getCellData(i, 3).trim()) &&
        $c.gus.cfIsNull(ds_excel.getCellData(i, 4).trim()) &&
        $c.gus.cfIsNull(ds_excel.getCellData(i, 5).trim())) {
        //f_retrieveCntrBasisInfo(ds_excel.getCellData(i, 1).trim()); //TOBE : 위에 조회 로직 있는데 이중으로 실행되어 주석으로 막음
        ds_out.setCellData(ds_out.getRowPosition(), "cntrNo", ds_excel.getCellData(i, 0).trim());
    } else {
        //f_retrieveCntrBasisInfo(ds_excel.ColumnValue(i, 1).trim());
        ds_out.setCellData(ds_out.getRowPosition(), "cntrNo", ds_excel.getCellData(i, 0).trim());

        if (!$c.gus.cfIsNull(ds_excel.getCellData(i, 1).trim()))
            await scwin.f_openCommonPopUp(3, ds_excel.getCellData(i, 1).trim(), '', 'T', 'T');

        ds_out.setCellData(ds_out.getRowPosition(), "rmk", ds_excel.getCellData(i, 2));

        // ASIS : SOC여부가 가우스는 코드값이 없어도 코드명으로 SET되는데 TOBE에서는 안되므로 코드값으로 다시 SET
        if (ds_excel.getCellData(i, 3).trim() == "Y") {
            ds_out.setCellData(ds_out.getRowPosition(), "socYn", "1");
        } else if (ds_excel.getCellData(i, 3).trim() == "N") {
            ds_out.setCellData(ds_out.getRowPosition(), "socYn", "0");
        } else {
            ds_out.setCellData(ds_out.getRowPosition(), "socYn", ds_excel.getCellData(i, 3).trim());
        }

        scwin.f_ValidateTerm(i);
        scwin.f_ValidateOffRtrn(i);
    }
}

//-------------------------------------------------------------------------
// TERM 값 유효성 검사 함수
//-------------------------------------------------------------------------
scwin.f_ValidateTerm = function (i) {
    if ($c.gus.cfIsNull(ds_excel.getCellData(i, 4))) {
        ds_out.setCellData(ds_out.getRowPosition(), "term", ds_excel.getCellData(i, 4));
    } else {
        for (var j = 0; j < dlt_commonCodeOP524.getRowCount(); j++) {
            if (dlt_commonCodeOP524.getCellData(j, "cd") === ds_excel.getCellData(i, 4) || dlt_commonCodeOP524.getCellData(j, "cdNm") === ds_excel.getCellData(i, 4)) {
                ds_out.setCellData(ds_out.getRowPosition(), "term", ds_excel.getCellData(i, 4));
            }
        }

        if (ds_excel.getCellData(i, 4) !== ds_out.getCellData(ds_out.getRowPosition(), "term")) {
            $c.gus.cfAlertMsg("적재된 파일 자료의 " + ds_out.getCellData(ds_out.getRowPosition(), "cntrNo") + "컨테이너의  TERM은 컨테이너 화물추적의 TERM콤보박스 중에서 선택하세요");
            ds_excel.setJSON([]);
            return;
        }
    }
}

//-------------------------------------------------------------------------
// OFF반납 값 유효성 검사 함수
//-------------------------------------------------------------------------
scwin.f_ValidateOffRtrn = function (i) {
    if ($c.gus.cfIsNull(ds_excel.getCellData(i, 5))) {
        ds_out.setCellData(ds_out.getRowPosition(), "offRtrn", ds_excel.getCellData(i, 5));
    } else {
        for (var j = 0; j < dlt_commonCodeSD133.getRowCount(); j++) {
            if (dlt_commonCodeSD133.getCellData(j, "cd") === ds_excel.getCellData(i, 5) || dlt_commonCodeSD133.getCellData(j, "cdNm") === ds_excel.getCellData(i, 5)) {
                ds_out.setCellData(ds_out.getRowPosition(), "offRtrn", ds_excel.getCellData(i, 5));
            }
        }
        if (ds_excel.getCellData(i, 5) !== ds_out.getCellData(ds_out.getRowPosition(), "offRtrn")) {
            $c.gus.cfAlertMsg("적재된 파일 자료의 " + ds_out.getCellData(ds_out.getRowPosition(), "cntrNo") + "컨테이너의 OFF반납은 은 컨테이너 화물추적의 OFF반납콤보박스 중에서 선택하세요");
            ds_excel.setJSON([]);
            return;
        }
    }
}

//-------------------------------------------------------------------------
// 컨테이너 SOC제어할 내역을 조회
//-------------------------------------------------------------------------
scwin.f_retrieveCntrBasisInfo = async function (cntrNo) {
    if (!$c.gus.cfIsNull(cntrNo)) {
        ds_cntr.setEmptyValue();
        ds_cntr.set("cntrNo", cntrNo);

        await $c.sbm.execute(sbm_retrieveCntrBasisInfo); //tr_retrieveCntrBasisInfo.Post();	

        if (ds_cntrResult.getRowCount() > 0) {
            scwin.f_addCntrInfo(ds_out.getRowPosition());
        }
    }
};

//-------------------------------------------------------------------------
// 컨테이너 제어등록 정보 SET
//-------------------------------------------------------------------------
scwin.f_addCntrInfo = function (row) {
    ds_out.setCellData(row, "cntrNo", ds_cntrResult.getCellData(0, "cntrNo"));
    ds_out.setCellData(row, "sealNo", ds_cntrResult.getCellData(0, "sealNo"));
    ds_out.setCellData(row, "cntrSizCd", ds_cntrResult.getCellData(0, "cntrSizCd"));
    ds_out.setCellData(row, "cntrTypCd", ds_cntrResult.getCellData(0, "cntrTypCd"));
    ds_out.setCellData(row, "fullEmptyClsCd", ds_cntrResult.getCellData(0, "fullEmptyClsCd"));
    ds_out.setCellData(row, "lineCd", ds_cntrResult.getCellData(0, "lineCd"));
    ds_out.setCellData(row, "vsslCd", ds_cntrResult.getCellData(0, "vsslCd"));
    ds_out.setCellData(row, "creatOdrNo", ds_cntrResult.getCellData(0, "creatOdrNo"));
    ds_out.setCellData(row, "arrvlportDtm", ds_cntrResult.getCellData(0, "arrvlportDtm"));
    ds_out.setCellData(row, "currPosCd", ds_cntrResult.getCellData(0, "currPosCd"));
    ds_out.setCellData(row, "currPosNm", ds_cntrResult.getCellData(0, "currPosNm"));
    ds_out.setCellData(row, "rmk", ds_cntrResult.getCellData(0, "rmk"));

    if (ds_cntrResult.getCellData(row, "socYn") == "Y") {
        ds_out.setCellData(row, "socYn", "1");
    } else if (ds_cntrResult.getCellData(row, "socYn") == "N") {
        ds_out.setCellData(row, "socYn", "0");
    } else {
        ds_out.setCellData(row, "socYn", ds_cntrResult.getCellData(0, "socYn"));
    }

    ds_out.setCellData(row, "term", ds_cntrResult.getCellData(0, "term"));
    ds_out.setCellData(row, "offRtrn", ds_cntrResult.getCellData(0, "offRtrn"));
    ds_out.setCellData(row, "bookingNo", ds_cntrResult.getCellData(0, "bookingNo"));
    ds_out.setCellData(row, "blNo", ds_cntrResult.getCellData(0, "blNo"));
};

//---------------------------------------------------------
// 그리드에서 팝업오픈하기전 작업(코드와 코드명이 있는 경우)
//---------------------------------------------------------
scwin.f_openPopUpGridBefore = function (colGubun, ds, cdColid, nmColid, olddata, gubun, pWinCloseTF) {
    if (colGubun == "CD") {
        var cdVal = ds.getCellData(ds.getRowPosition(), cdColid);
        if (cdVal == "") {
            ds.setCellData(ds.getRowPosition(), nmColid, "");
        } else {
            if (cdVal != olddata) {
                ds.setCellData(ds.getRowPosition(), nmColid, "");
                scwin.f_openPopUpGrid(ds, cdColid, nmColid, gubun, pWinCloseTF);
            }
        }
    } else if (colGubun == "NM") {
        var nmVal = ds.getCellData(ds.getRowPosition(), nmColid);
        if (nmVal == "") {
            ds.setCellData(ds.getRowPosition(), cdColid, "");
        } else {
            if (nmVal != olddata) {
                ds.setCellData(ds.getRowPosition(), cdColid, "");
                scwin.f_openPopUpGrid(ds, cdColid, nmColid, gubun, pWinCloseTF);
            }
        }
    }
};

//---------------------------------------------------------
// 그리드에서 팝업오픈
//---------------------------------------------------------
scwin.f_openPopUpGrid = function (ds, cdColid, nmColid, gubun, pWinCloseTF) {
    var pCode = "";
    var pName = "";
    var pWtitleSearch = null;
    var pWhere = null;
    var pSelectID = "";

    if (gubun == 7 || gubun == 8) {
        var cnt = ds.getCellData(ds.getRowPosition(), nmColid).indexOf("]");
        pCode = ds.getCellData(ds.getRowPosition(), cdColid);
        pName = ds.getCellData(ds.getRowPosition(), nmColid).substr(cnt + 1);
    } else if (gubun == 13 || gubun == 14) {
        pCode = ds.getCellData(ds.getRowPosition(), cdColid) + '';
        pName = ds.getCellData(ds.getRowPosition(), nmColid) + '';
    } else {
        pCode = ds.getCellData(ds.getRowPosition(), cdColid);
        pName = ds.getCellData(ds.getRowPosition(), nmColid);
    }

    if (gubun == 1) {	// 현위치코드
        pSelectID = "retrieveWrkPlInfo";
        pWtitleSearch = "현위치,현위치코드,현위치명";
        pWhere = null;
    }

    udc_comCode1.setSelectId(pSelectID); //pSelectID
    udc_comCode1.cfCommonPopUp(scwin.udc_gr_comCode_callBackFunc, //콜백 함수
        pCode,							//pCode
        pName,							//pName
        pWinCloseTF,					//pWinCloseTF
        null,						    //pDispCnt
        null,							//pTitle
        null,							//pWidth
        null,						    //pHidden
        pWhere,							//pWhere
        null,							//pW
        null,							//pH
        null,							//pTop
        null,							//pLeft
        null,							//pExistTF - 중복체크여부	("F")
        "F",							//pAllSearchTF - 전체검색허용여부	("F")
        pWtitleSearch);					//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")    
};

//-------------------------------------------------------------------------
// 대문자 입력
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

//-------------------------------------------------------------------------
// 조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    tbx_totalRows.setValue(ds_out.getRowCount());

    if (ds_out.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }

    // ASIS : SOC여부가 SOC코드명으로 조회되서 가우스는 코드값이 없어도 코드명으로 SET되는데 TOBE에서는 안되므로 코드값으로 다시 SET
    for (var row = 0; row < ds_out.getRowCount(); row++) {
        if (ds_out.getCellData(row, "socYn") == "Y") {
            ds_out.setCellData(row, "socYn", "1");
        } else if (ds_out.getCellData(row, "socYn") == "N") {
            ds_out.setCellData(row, "socYn", "0");
        }

    }

    ds_out.reform(); // 그리드의 originalData를 현재의 데이터로 바꿔주고 모든 행의 상태를 초기화
};

//-------------------------------------------------------------------------
// 저장 submitdone
//-------------------------------------------------------------------------
scwin.sbm_save_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    $c.gus.cfAlertMsg(MSG_CM_INF_001);
};

//-------------------------------------------------------------------------
// 그리드 검색 버튼 클릭 이벤트
// ASIS : gr_out event=OnPopup(row,colid,data)
//-------------------------------------------------------------------------
scwin.gr_out_ontextimageclick = function (rowIndex, columnIndex) {
    if (columnIndex == 9) { // 현위치코드(currPosNm)
        scwin.f_openPopUpGrid(ds_out, "currPosCd", "currPosNm", 1, "T");
    }
};

//-------------------------------------------------------------------------
// 그리드 셀 편집 전 이벤트(olddata 비교하기 위해 사용)
//-------------------------------------------------------------------------
scwin.gr_out_onbeforeedit = function (rowIndex, columnIndex, value) {
    scwin.olddata = value;
};

//-------------------------------------------------------------------------
// 그리드 셀 편집모드 종료 이벤트
// ASIS : gr_out event=OnExit(row,colid,olddata)
//-------------------------------------------------------------------------
scwin.gr_out_onafteredit = function (rowIndex, columnIndex, value) {
    if (columnIndex == 0) { // 컨테이너번호(cntrNo)
        scwin.f_retrieveCntrBasisInfo(ds_out.getCellData(rowIndex, "cntrNo"));
    } else if (columnIndex == 9) { // 현위치코드(currPosNm)
        scwin.f_openPopUpGridBefore("NM", ds_out, "currPosCd", "currPosNm", scwin.olddata, 1, "T");
    }
};

//-------------------------------------------------------------------------
// 그리드 : 현위치명 검색 콜백
//-------------------------------------------------------------------------
scwin.udc_gr_comCode_callBackFunc = function (rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") { //팝업에서 닫기버튼 클릭시
            ds_out.setCellData(ds_out.getRowPosition(), "currPosCd", ds.getOriginalCellData(ds_out.getRowPosition(), "currPosCd"));
            ds_out.setCellData(ds_out.getRowPosition(), "currPosNm", ds.getOriginalCellData(ds_out.getRowPosition(), "currPosNm"));
        } else {
            ds_out.setCellData(ds_out.getRowPosition(), "currPosCd", rtnList[0]);
            ds_out.setCellData(ds_out.getRowPosition(), "currPosNm", rtnList[1]);
        }
    } else {
        ds_out.setCellData(ds_out.getRowPosition(), "currPosCd", "");
        ds_out.setCellData(ds_out.getRowPosition(), "currPosNm", "");
    }
};

//-------------------------------------------------------------------------
// 엑셀 업로드 : 현위치명 검색 콜백
//-------------------------------------------------------------------------
scwin.udc_gr_uploadComCode_callBackFunc = function (rtnList) {
    if (rtnList != null && rtnList[0] != 'N/A') {
        ds_out.setCellData(ds_out.getRowposition(), "currPosCd", rtnList[0]); //작업장코드
        ds_out.setCellData(ds_out.getRowposition(), "currPosNm", rtnList[1]); //작업장명

        if (ds_out.getCellData(ds_out.getRowposition(), "currPosNm") == 'undefined') {
            ds_out.setCellData(ds_out.getRowposition(), "currPosNm", '');
        }
    } else {
        ds_out.setCellData(ds_out.getRowposition(), "currPosNm", '');
    }
};
